INSERT OR REPLACE INTO `Product` (`id`, `name`, `nameEs`, `nameAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `categoryId`, `image`, `gallery`, `features`, `featuresEs`, `featuresAr`, `content`, `contentEs`, `contentAr`, `isFeatured`, `createdAt`, `updatedAt`) VALUES ('cmovii6ja000ctmm4k2nrxpwl', 'Mono-PE Recyclable Rollstock', NULL, NULL, 'mono-pe-recyclable-rollstock', NULL, NULL, NULL, NULL, NULL, NULL, 'cmovii68y0004tmm4qtfet8ep', '/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/1.png', '["/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/1.png","/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/2.png","/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/3.png","/products/recyclable-mono-materials/mono-pe-recyclable-rollstock/4.png"]', '["100% Recyclable","Sustainable","High Sealing Strength"]', NULL, NULL, '<div class="product-detailed-description">
  <h3>Product Overview</h3>
  <p>The <strong>Mono-PE Recyclable Rollstock</strong> is engineered to meet the highest industry standards for flexible packaging and functional applications. Utilizing advanced manufacturing processes, this material delivers exceptional performance tailored for specialized needs.</p>
  
  <h3>Key Characteristics</h3>
  <ul>
    <li><strong>Core Advantage:</strong> Sustainable</li>
