INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44oku0000tmnsr1lj4wla', 'How to Choose the Right Food Packaging Bag?', NULL, NULL, 'how-to-choose-right-food-packaging-bag', 'How to Choose the Right Food Packaging Bag?', NULL, NULL, 'Choosing the right food packaging bag is crucial for preserving product quality, extending shelf life, and attracting consumers. This guide covers material selection, barrier properties, and printing options.', NULL, NULL, 'Choosing the right food packaging bag is crucial for preserving product quality, extending shelf life, and attracting consumers. This guide covers material selection, barrier properties, and printing options.', NULL, NULL, '<p>When selecting food packaging bags, consider the following factors: 1. Material safety (must be food-grade), 2. Barrier requirements (oxygen and moisture resistance), 3. Physical strength (puncture resistance), 4. Convenience (zippers, tear notches). At HLT PACK, we provide customized solutions based on your specific product needs.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.11.20', '/images/factory/印刷车间/10001.png', '2026-04-29T13:50:46.638Z', '2026-05-04T12:08:49.414Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44ong0001tmnsozp8007n', 'What are the Advantages of Transparent Plastic Bags?', NULL, NULL, 'advantages-of-transparent-plastic-bags', 'What are the Advantages of Transparent Plastic Bags?', NULL, NULL, 'Transparent plastic bags offer high visibility, allowing consumers to see the product inside. This builds trust and enhances the visual appeal of fresh produce and retail goods.', NULL, NULL, 'Transparent plastic bags offer high visibility, allowing consumers to see the product inside. This builds trust and enhances the visual appeal of fresh produce and retail goods.', NULL, NULL, '<p>Transparent packaging stands out by offering complete visibility. It is widely used in the fresh food, hardware, and cosmetics industries. Our high-clarity OPP and PE bags ensure your products look their best on the shelf while providing excellent moisture protection.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.11.15', '/images/factory/印刷车间/10002.png', '2026-04-29T13:50:46.732Z', '2026-05-04T12:08:49.529Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44opi0002tmnszc7l11hz', 'The Benefits of Eco-Friendly Packaging Bags', NULL, NULL, 'benefits-of-eco-friendly-packaging', 'The Benefits of Eco-Friendly Packaging Bags', NULL, NULL, 'Eco-friendly packaging is becoming the new standard. Discover how biodegradable and recyclable materials can reduce your carbon footprint and appeal to modern consumers.', NULL, NULL, 'Eco-friendly packaging is becoming the new standard. Discover how biodegradable and recyclable materials can reduce your carbon footprint and appeal to modern consumers.', NULL, NULL, '<p>Sustainable packaging helps reduce environmental impact and aligns with global green initiatives. HLT PACK offers a range of recyclable mono-material pouches and compostable films that deliver the same high-barrier performance as traditional plastics.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.11.10', '/images/factory/印刷车间/10003.png', '2026-04-29T13:50:46.806Z', '2026-05-04T12:08:49.749Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44ork0003tmns2v7nhcvj', 'Understanding Aluminum Foil Bags', NULL, NULL, 'understanding-aluminum-foil-bags', 'Understanding Aluminum Foil Bags', NULL, NULL, 'Aluminum foil bags provide the ultimate barrier against light, oxygen, and moisture. Learn why they are the top choice for coffee, tea, and sensitive electronics.', NULL, NULL, 'Aluminum foil bags provide the ultimate barrier against light, oxygen, and moisture. Learn why they are the top choice for coffee, tea, and sensitive electronics.', NULL, NULL, '<p>Featuring a multi-layer composite structure, aluminum foil bags completely block out UV light and oxygen. They are essential for extending the shelf life of roasted coffee beans, premium teas, and pharmaceutical products.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.11.05', '/images/factory/印刷车间/10004.png', '2026-04-29T13:50:46.880Z', '2026-05-04T12:08:49.903Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44oto0004tmnsd4snwvp3', 'What is a Retort Pouch?', NULL, NULL, 'what-is-a-retort-pouch', 'What is a Retort Pouch?', NULL, NULL, 'Retort pouches are designed to withstand high temperatures during sterilization. They are lightweight alternatives to cans and glass jars for ready-to-eat meals.', NULL, NULL, 'Retort pouches are designed to withstand high temperatures during sterilization. They are lightweight alternatives to cans and glass jars for ready-to-eat meals.', NULL, NULL, '<p>Retort pouches are made from specialized laminates that can survive temperatures up to 121°C (250°F). They offer a long shelf life for liquid foods, curries, and pet food without requiring refrigeration.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.10.28', '/images/factory/印刷车间/10005.png', '2026-04-29T13:50:46.956Z', '2026-05-04T12:08:50.079Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44ow90005tmnsqr63crnp', 'Custom Printed Pouch Design Guidelines', NULL, NULL, 'custom-printed-pouch-design-guidelines', 'Custom Printed Pouch Design Guidelines', NULL, NULL, 'A great design makes your product pop. Learn the basics of preparing your artwork for rotogravure printing to ensure vibrant colors and sharp details.', NULL, NULL, 'A great design makes your product pop. Learn the basics of preparing your artwork for rotogravure printing to ensure vibrant colors and sharp details.', NULL, NULL, '<p>To achieve the best printing results, provide vector artwork in CMYK color mode. Pay attention to bleed areas and avoid placing critical text near the sealing edges. Our prepress team is always available to help optimize your designs.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.10.20', '/images/factory/制袋车间/10001.png', '2026-04-29T13:50:47.049Z', '2026-05-04T12:08:50.279Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44oya0006tmnsdgknsaqq', 'Vacuum Bags: Extending Shelf Life', NULL, NULL, 'vacuum-bags-extending-shelf-life', 'Vacuum Bags: Extending Shelf Life', NULL, NULL, 'By removing air from the package, vacuum bags significantly slow down the growth of bacteria and fungi, keeping meat, cheese, and nuts fresh for longer.', NULL, NULL, 'By removing air from the package, vacuum bags significantly slow down the growth of bacteria and fungi, keeping meat, cheese, and nuts fresh for longer.', NULL, NULL, '<p>Vacuum packaging is a proven method for food preservation. Our heavy-duty vacuum bags are highly puncture-resistant, ensuring the vacuum seal remains intact during transportation and storage.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.10.12', '/images/factory/制袋车间/10002.png', '2026-04-29T13:50:47.123Z', '2026-05-04T12:08:50.437Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p050007tmns37j2v64x', 'The Rise of Stand-Up Pouches with Zippers', NULL, NULL, 'rise-of-stand-up-pouches-with-zippers', 'The Rise of Stand-Up Pouches with Zippers', NULL, NULL, 'Stand-up pouches dominate the retail space due to their convenience and shelf presence. The addition of a resealable zipper adds immense value for consumers.', NULL, NULL, 'Stand-up pouches dominate the retail space due to their convenience and shelf presence. The addition of a resealable zipper adds immense value for consumers.', NULL, NULL, '<p>Offering a large billboard area for branding, stand-up pouches are perfect for snacks, pet food, and powders. The built-in bottom gusset allows the bag to stand upright, while the zipper ensures the contents stay fresh after opening.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.10.05', '/images/factory/制袋车间/10003.png', '2026-04-29T13:50:47.189Z', '2026-05-04T12:08:50.612Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p200008tmns6qtgehut', 'How to Measure a Packaging Bag Correctly?', NULL, NULL, 'how-to-measure-packaging-bag', 'How to Measure a Packaging Bag Correctly?', NULL, NULL, 'Accurate measurements are the first step to creating the perfect custom bag. Learn how to measure width, length, and gussets properly.', NULL, NULL, 'Accurate measurements are the first step to creating the perfect custom bag. Learn how to measure width, length, and gussets properly.', NULL, NULL, '<p>When specifying bag dimensions, always provide the Outer Dimensions (OD). For stand-up pouches, measure Width x Height + Bottom Gusset. Remember to account for the seal width and the volume of the product you intend to fill.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.09.28', '/images/factory/制袋车间/10004.png', '2026-04-29T13:50:47.256Z', '2026-05-04T12:08:50.770Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p3u0009tmnsw8ae3ar9', 'Why Choose Solvent-Free Lamination?', NULL, NULL, 'why-choose-solvent-free-lamination', 'Why Choose Solvent-Free Lamination?', NULL, NULL, 'Solvent-free lamination is safer for the environment and food products. It eliminates the risk of solvent residue and VOC emissions.', NULL, NULL, 'Solvent-free lamination is safer for the environment and food products. It eliminates the risk of solvent residue and VOC emissions.', NULL, NULL, '<p>At HLT PACK, we utilize advanced solvent-free laminators. This process uses 100% solid adhesives, curing quickly without releasing harmful emissions, making it the safest choice for food-contact packaging.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.09.20', '/images/factory/制袋车间/10005.png', '2026-04-29T13:50:47.323Z', '2026-05-04T12:08:50.903Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p5p000atmnsxg1sf6sm', 'Spout Pouches for Liquid Packaging', NULL, NULL, 'spout-pouches-liquid-packaging', 'Spout Pouches for Liquid Packaging', NULL, NULL, 'Spout pouches offer a lightweight, unbreakable alternative to rigid bottles. They are ideal for beverages, sauces, and liquid detergents.', NULL, NULL, 'Spout pouches offer a lightweight, unbreakable alternative to rigid bottles. They are ideal for beverages, sauces, and liquid detergents.', NULL, NULL, '<p>Designed with leak-proof seals and easy-pour spouts, these pouches are highly convenient for on-the-go consumption. They also reduce transportation costs and plastic waste compared to traditional rigid containers.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.09.15', '/images/factory/制袋车间/10006.png', '2026-04-29T13:50:47.390Z', '2026-05-04T12:08:51.044Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p80000btmns71wruvm3', 'The Difference Between PE and PP Films', NULL, NULL, 'difference-between-pe-and-pp-films', 'The Difference Between PE and PP Films', NULL, NULL, 'Polyethylene (PE) and Polypropylene (PP) are the two most common packaging plastics. Understand their distinct properties to make the right choice.', NULL, NULL, 'Polyethylene (PE) and Polypropylene (PP) are the two most common packaging plastics. Understand their distinct properties to make the right choice.', NULL, NULL, '<p>PE is soft, flexible, and offers excellent heat-sealing properties, making it ideal for inner sealing layers. PP is stiffer, highly transparent, and provides a better moisture barrier, often used as the outer printing layer.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.09.08', '/images/factory/制袋车间/10007.png', '2026-04-29T13:50:47.472Z', '2026-05-04T12:08:51.228Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44p9v000ctmns8txyytpq', 'What is the Minimum Order Quantity (MOQ)?', NULL, NULL, 'what-is-minimum-order-quantity', 'What is the Minimum Order Quantity (MOQ)?', NULL, NULL, 'Understanding MOQs is essential for custom printing. We explain how printing cylinders and machine setup dictate the minimum run size.', NULL, NULL, 'Understanding MOQs is essential for custom printing. We explain how printing cylinders and machine setup dictate the minimum run size.', NULL, NULL, '<p>For custom rotogravure printing, the MOQ is typically determined by the size of the bag and the length of the master film roll (usually requiring at least 10,000 to 20,000 pieces). However, we also offer digital printing solutions for smaller test runs.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.09.01', '/images/factory/制袋车间/10008.png', '2026-04-29T13:50:47.539Z', '2026-05-04T12:08:51.412Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44pbp000dtmns8ut70yh1', 'Matte vs. Glossy Finish: Which is Better?', NULL, NULL, 'matte-vs-glossy-finish', 'Matte vs. Glossy Finish: Which is Better?', NULL, NULL, 'The finish of your packaging heavily influences brand perception. Explore the aesthetic and practical differences between matte and glossy varnishes.', NULL, NULL, 'The finish of your packaging heavily influences brand perception. Explore the aesthetic and practical differences between matte and glossy varnishes.', NULL, NULL, '<p>A glossy finish provides vibrant, eye-catching colors and a highly reflective surface. A matte finish offers a premium, understated look that feels soft to the touch and reduces glare, making text easier to read under bright lights.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.08.25', '/images/factory/制袋车间/10009.png', '2026-04-29T13:50:47.606Z', '2026-05-04T12:08:51.551Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44pdk000etmnsrmzv7ckk', 'How Long Does Custom Packaging Take?', NULL, NULL, 'how-long-custom-packaging-take', 'How Long Does Custom Packaging Take?', NULL, NULL, 'From design approval to final delivery, we break down the typical lead times for manufacturing custom flexible packaging.', NULL, NULL, 'From design approval to final delivery, we break down the typical lead times for manufacturing custom flexible packaging.', NULL, NULL, '<p>The standard lead time is 15-20 days. This includes cylinder engraving (3-5 days), printing and lamination (5-7 days), curing (2-3 days), and pouch making/QC (3-5 days). Shipping times vary based on your global location.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.08.18', '/images/factory/制袋车间/10010.png', '2026-04-29T13:50:47.673Z', '2026-05-04T12:08:51.698Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44pff000ftmnsw8rez72h', 'Food Grade Inks and Safety Standards', NULL, NULL, 'food-grade-inks-safety-standards', 'Food Grade Inks and Safety Standards', NULL, NULL, 'Not all inks are created equal. Discover why we strictly use toluene-free, heavy-metal-free inks for all our food packaging products.', NULL, NULL, 'Not all inks are created equal. Discover why we strictly use toluene-free, heavy-metal-free inks for all our food packaging products.', NULL, NULL, '<p>Consumer safety is our top priority. We use only FDA and EU compliant inks that guarantee no chemical migration into the food. Our rigorous QC processes ensure that all printed materials are 100% safe and odor-free.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.08.10', '/images/factory/印刷车间/10001.png', '2026-04-29T13:50:47.739Z', '2026-05-04T12:08:51.862Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44phq000gtmnsttyuk09l', 'The Importance of Tear Notches', NULL, NULL, 'importance-of-tear-notches', 'The Importance of Tear Notches', NULL, NULL, 'A small detail that makes a huge difference. Tear notches greatly improve the consumer experience by allowing easy opening without scissors.', NULL, NULL, 'A small detail that makes a huge difference. Tear notches greatly improve the consumer experience by allowing easy opening without scissors.', NULL, NULL, '<p>We can add single or double tear notches to almost any pouch style. They are strategically placed above the zipper line, ensuring the consumer can easily access the product while retaining the resealable function.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.08.05', '/images/factory/印刷车间/10002.png', '2026-04-29T13:50:47.823Z', '2026-05-04T12:08:52.012Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44pk1000htmnsuxxyhc2p', 'Packaging Solutions for Pet Food', NULL, NULL, 'packaging-solutions-for-pet-food', 'Packaging Solutions for Pet Food', NULL, NULL, 'Pet food requires heavy-duty packaging that can support large weights and block strong odors. Explore our specialized quad-seal and flat-bottom bags.', NULL, NULL, 'Pet food requires heavy-duty packaging that can support large weights and block strong odors. Explore our specialized quad-seal and flat-bottom bags.', NULL, NULL, '<p>Our pet food bags are engineered with high puncture resistance and strong side seals to prevent bursting. We also incorporate odor-barrier layers and heavy-duty slider zippers to keep kibble fresh and kitchens smelling clean.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.07.28', '/images/factory/印刷车间/10003.png', '2026-04-29T13:50:47.906Z', '2026-05-04T12:08:52.078Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44pm4000itmnsto8dx04v', 'What are Shaped Pouches?', NULL, NULL, 'what-are-shaped-pouches', 'What are Shaped Pouches?', NULL, NULL, 'Break away from traditional squares and rectangles. Shaped pouches offer unique silhouettes that instantly grab attention on retail shelves.', NULL, NULL, 'Break away from traditional squares and rectangles. Shaped pouches offer unique silhouettes that instantly grab attention on retail shelves.', NULL, NULL, '<p>Using specialized die-cutting technology, we can manufacture pouches in almost any shape—from bottles and jars to fruits and brand mascots. Shaped pouches are highly popular in the cosmetics, children''s food, and beverage sectors.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.07.20', '/images/factory/印刷车间/10004.png', '2026-04-29T13:50:47.980Z', '2026-05-04T12:08:52.204Z');
INSERT OR REPLACE INTO `News` (`id`, `title`, `titleEs`, `titleAr`, `slug`, `seoTitle`, `seoTitleEs`, `seoTitleAr`, `seoDescription`, `seoDescriptionEs`, `seoDescriptionAr`, `summary`, `summaryEs`, `summaryAr`, `content`, `contentEs`, `contentAr`, `category`, `categoryEs`, `categoryAr`, `date`, `image`, `createdAt`, `updatedAt`) VALUES ('cmok44po7000jtmnsw8ciy1p2', 'HLT PACK''s Quality Control Process', NULL, NULL, 'hailitong-quality-control-process', 'HLT PACK''s Quality Control Process', NULL, NULL, 'Take a look inside our QA lab. From raw material inspection to final drop tests, we ensure every pouch meets the highest standards.', NULL, NULL, 'Take a look inside our QA lab. From raw material inspection to final drop tests, we ensure every pouch meets the highest standards.', NULL, NULL, '<p>Our comprehensive QC process includes tensile strength testing, heat seal integrity checks, barrier property analysis (OTR/WVTR), and simulated transport drop tests. We guarantee that your packaging will perform flawlessly on your filling line.</p>', NULL, NULL, 'FAQ', NULL, NULL, '2024.07.15', '/images/factory/印刷车间/10005.png', '2026-04-29T13:50:48.056Z', '2026-05-04T12:08:52.314Z');

