INSERT OR REPLACE INTO `Banner` (`id`, `title`, `titleEs`, `titleAr`, `subtitle`, `subtitleEs`, `subtitleAr`, `description`, `descriptionEs`, `descriptionAr`, `image`, `link`, `isActive`, `order`, `createdAt`, `updatedAt`) VALUES ('cmo2uyvcb0004tmf8m6z23890', 'Static-Safe Packaging', NULL, NULL, 'ESD PROTECTION', NULL, NULL, 'Multi-layer shielding bags protect sensitive electronics from static, moisture, and handling damage.', NULL, NULL, '/products/ziplock-bags/anti-static-esd-shielding-bag/1.png', '/products/anti-static-esd-shielding-bag', 1, 5, '2026-04-17T12:02:13.931Z', '2026-07-06T12:58:35.704Z');

