INSERT OR REPLACE INTO `SystemSetting` (`id`, `siteNameZh`, `siteNameEn`, `logoUrl`, `faviconUrl`, `contactEmail`, `contactPhone`, `contactAddressZh`, `contactAddressEn`, `whatsapp`, `wechat`, `facebook`, `linkedin`, `youtube`, `instagram`, `twitter`, `seoTitleZh`, `seoTitleEn`, `seoDescZh`, `seoDescEn`, `seoKeywordsZh`, `seoKeywordsEn`, `defaultSeoImageUrl`, `siteNoindex`, `robotsDisallowPaths`, `noindexPaths`, `footerCopyZh`, `footerCopyEn`, `aboutYears`, `aboutEquipments`, `aboutArea`, `aboutGlobal`, `homeAboutEyebrowZh`, `homeAboutEyebrowEn`, `homeAboutTitleLine1Zh`, `homeAboutTitleLine1En`, `homeAboutTitleAccentZh`, `homeAboutTitleAccentEn`, `homeAboutTitleLine2Zh`, `homeAboutTitleLine2En`, `homeAboutStory1Zh`, `homeAboutStory1En`, `homeAboutStory2Zh`, `homeAboutStory2En`, `homeAboutMissionZh`, `homeAboutMissionEn`, `homeAboutCtaZh`, `homeAboutCtaEn`, `aboutStoryTagZh`, `aboutStoryTagEn`, `aboutStoryTitleZh`, `aboutStoryTitleEn`, `aboutStoryBody1Zh`, `aboutStoryBody1En`, `aboutStoryBody2Zh`, `aboutStoryBody2En`, `aboutStoryPrimaryCtaZh`, `aboutStoryPrimaryCtaEn`, `aboutStorySecondaryCtaZh`, `aboutStorySecondaryCtaEn`, `aboutHeroImage`, `marketHeroImage`, `safetyHeroImage`, `sustainabilityHeroImage`, `factoryHeroImage`, `contactHeroImage`, `createdAt`, `updatedAt`) VALUES ('global', '海利通包装', 'HLT PACK', '', '/uploads/1778587893461-l1cau8h.ico', 'info@hltpack.com', '585-290-2624', '深圳市龙岗区宝龙街道龙新社区兰二路51号A栋401', 'No.51, Lan''er Road, Longxin Community, Baolong Street, Longgang District, Shenzhen, China', 'https://api.whatsapp.com/send/?phone=5852902624&text=I+am+interested+in+flexible+packaging&type=phone_number&app_absent=0', '', '', 'https://www.linkedin.com/company/hlt-pack/?viewAsMember=true', 'https://www.youtube.com/@HLTPACK', '', '', '', '', '', '', '', '', '', 0, '', '', '', '', '31', '100', '30', '100', '', 'About HLT Packaging', '', 'Pioneering', '', 'Flexible', '', 'Packaging Since 2001', '', 'Established in 2001 and located in Shenzhen, China, HLT PACK has evolved into a global leader in flexible packaging manufacturing. We specialize in engineering premium, sustainable, and high-barrier pouch solutions.', '', 'Equipped with world-class multi-color rotogravure presses, solventless laminators, and advanced pouch-making lines, we deliver uncompromising quality to brands worldwide. Our mission is simple: ', '', '"Premium Quality, Customer First".', '', 'Discover Our Story', '', 'Our Story', '', 'Packaging Solutions That Care About Our Future', '', 'Established in 2001 and strategically located in Shenzhen (Longgang District), adjacent to Hong Kong, HLT PACK brings over 31 years of industry experience to the flexible packaging sector. Supported by a team of experienced professional technicians, we have built a solid reputation for delivering stable product quality, reasonable pricing, and rapid delivery.', '', 'Our state-of-the-art facility is equipped with comprehensive advanced machinery, including film blowing machines, high-speed rotogravure presses, laminating machines, slitting machines, folding machines, food pouch making machines, three-side sealing machines, center sealing machines, R-machines, flat bag machines, slicing machines, and silica gel drying machines. We specialize in producing a wide range of plastic packaging bags, including food bags, aluminum foil bags, foil-clear bags, vacuum bags, high-temperature retort pouches, multi-layer composite bags, anti-static bags, spout pouches, flower sleeves, shaped bags, facial mask bags, zipper stand-up pouches, PE zip-lock bags, high-transparency OPP header bags, automatic packaging roll films, high-transparency flat bags, and handle bags. Guided by our principle: ''Premium Quality, Customer First'', we proudly export our solutions to Europe, America, Russia, Japan, and beyond.', '', 'Explore Our Products', '', 'Get in Touch', '/images/factory/印刷车间/10001.png', '/images/factory/制袋车间/10010.png', '/images/factory/制袋车间/10002.png', '/images/factory/制袋车间/10008.png', '/images/factory/印刷车间/10101 (2).png', '/images/factory/制袋车间/10006.png', '2026-04-17T13:58:03.346Z', '2026-05-12T13:33:04.017Z');

